import {USDollar, USDollarRevert} from "../utils/util"

let id = 0
export default class InputRange extends HTMLElement {
  static get observedAttributes() {
    return ["value", "disabled", "name", "min", "step", "max", "dollar"];
  }

  attributeChangedCallback(name, oldValue, newValue) {
  }

  constructor() {
    super();
    const shadowRoot = this.attachShadow({ 
      mode: 'open',      
      delegatesFocus: true
    });
    const _id = ++id
    const labelId = `input-range-label-${_id}`
    const inputId = `input-range-${_id}`
    shadowRoot.innerHTML = `
      <style>
        :host {
          font-family: var(--font-family);
          font-size: 14px;
          display: flex;
        } 
        .root {
          display: flex;
          flex-direction: column;
          width: 100%;
        }
        #label {
          padding-bottom: 6px;
          color: var(--text-tertiary);
        }
        .input, .range {
          width: 100%;
        }
        .input-number {
          position: relative; 
          display: flex;
        }
        .dollar {
          position: absolute;
          top: 10px;
          right: 10px;
        }
        .input {
          border: none;
          padding: 10px;
          border-radius: 4px;
          font-size: 16px;
          background: var(--background-secondary);
          color: var(--text-primary);
        }
        .range {
          position: absolute;
          width: calc(100% - 5px);
          bottom: -2px;
          left: 0px;
        }
        input[type=range]::-webkit-slider-runnable-track {
          width: 100%;
          height: 2px;
          cursor: pointer;
          animate: 0.2s;
          border-radius: 5px;
          border: 1px solid blue;
        }
        input[type=range]::-webkit-slider-thumb {
          -webkit-appearance: none;
          border: 1px solid #2497E3;
          height: 8px;
          width: 8px;
          background: #A1D0FF;
          cursor: pointer;
          margin-top: -8px;
        }
      </style>
      <div class="root">
        <label for=${inputId} id=${labelId}>
          <slot name="label"></slot>
        </label>
        <span class="input-container">
          <span class="input-number">
            <input id=${inputId} class="input" type="text"></input>
            <span class="dollar">$</span>
            <input aria-labelledby=${labelId} class="range" type="range"></input>
          </span>
        </span>
      </div>
    `
  }

  setInputValue = value => {
    const input = this.shadowRoot.querySelector(".input")
    const range = this.shadowRoot.querySelector(".range")
    if (this.isDollar) {
      let dollar = USDollar.format(value)
      if (dollar.includes("$")) dollar = dollar.split("$")[1]
      input.value = dollar
    } else {
      input.value = value
    }
    range.value = value
  }

  connectedCallback() {
    this.classList.add("hydrated")
    const range = this.shadowRoot.querySelector(".range")
    const input = this.shadowRoot.querySelector(".input")
    const sign = this.shadowRoot.querySelector(".dollar")
    this.isDollar = this.hasAttribute("dollar")
    if (this.isDollar) sign.innerHTML = "$"
    else sign.innerHTML = "%"
    this.render({range, input})
    range.addEventListener("input", e => {
      const value = e.target.value
      this.setInputValue(value)
    })
    input.addEventListener("keypress", e => {
      const value = e.target.value
      if (e.which < 48 || e.which > 57) {
        e.preventDefault();
      }
      e.target.value = value
    })
    input.addEventListener("keyup", e => {
      if (this.isDollar) this.setInputValue(USDollarRevert(e.target.value))
    })
    this.form = this.findContainingForm();
    if (this.form) {
      this.form.addEventListener('formdata', this.handleFormData);
    }
  }

  render = ({range, input}) => {
    const name = this.getAttribute("name")
    const disabled = this.getAttribute("disabled")
    const value = this.getAttribute("value")
    const min = this.getAttribute("min")
    const max = this.getAttribute("max")
    const step = this.getAttribute("step")
    input.setAttribute("name", name)
    this.setInputValue(value)
    range.setAttribute("value", value)
    min && range.setAttribute("min", min)
    max && range.setAttribute("max", max)
    step && range.setAttribute("step", step)
    if (!!disabled) {
      input.setAttribute("disabled", "")
      range.setAttribute("disabled", "")
    } else {
      input.removeAttribute("disabled")
      range.removeAttribute("disabled")
    }
  }

  handleFormData = ({formData}) => {
    const input = this.shadowRoot.querySelector(".input")
    if (!this.disabled) {
      formData.append(input.name, input.value);
    }
  }

  findContainingForm = () => {
    const root = this.getRootNode();
    const forms = Array.from(root.querySelectorAll('form'));
    return forms.find((form) => form.contains(this)) || null;
  }

}
